import { Check } from "lucide-react";

const steps = ["白底图", "建议", "选方案", "生成", "确认"];

export default function GeneratePage() {
  return (
    <div className="border rounded-lg bg-white">
      {/* 标题栏 */}
      <div className="flex items-center justify-between px-6 py-4 border-b">
        <span className="font-medium text-sm">AI 生成操作面板</span>
        <button className="flex items-center gap-1 text-sm text-muted-foreground border rounded px-3 py-1 hover:bg-muted transition-colors">
          <span className="text-base leading-none">↻</span>
          刷新数据
        </button>
      </div>

      {/* 步骤条 */}
      <div className="px-12 py-8">
        <div className="flex items-center">
          {steps.map((step, index) => (
            <div key={step} className="flex items-center flex-1 last:flex-none">
              {/* 节点 */}
              <div className="flex flex-col items-center gap-2">
                <div className="w-8 h-8 rounded-full border-2 border-green-500 bg-white flex items-center justify-center">
                  <Check className="w-4 h-4 text-green-500" strokeWidth={2.5} />
                </div>
                <span className="text-sm text-green-600 whitespace-nowrap">{step}</span>
              </div>
              {/* 连接线 */}
              {index < steps.length - 1 && (
                <div className="flex-1 h-0.5 bg-green-500 mb-6" />
              )}
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
